import{_ as e,o as t,c as n,ag as l}from"./chunks/framework.BZohXCq9.js";const u=JSON.parse('{"title":"桜色の季節 — 町内地図 UI 設計","description":"","frontmatter":{},"headers":[],"relativePath":"plans/2026-03-15-sakura-map-design.md","filePath":"plans/2026-03-15-sakura-map-design.md","lastUpdated":null}'),i={name:"plans/2026-03-15-sakura-map-design.md"};function s(o,a,r,d,p,c){return t(),n("div",null,[...a[0]||(a[0]=[l(`<h1 id="桜色の季節-—-町内地図-ui-設計" tabindex="-1">桜色の季節 — 町内地図 UI 設計 <a class="header-anchor" href="#桜色の季節-—-町内地図-ui-設計" aria-label="Permalink to &quot;桜色の季節 — 町内地図 UI 設計&quot;">​</a></h1><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>Add a hand-drawn style town map overlay to the 桜色の季節 VN card. The map shows all available locations with real geographical relationships, grouped logically. Pure display — no navigation/movement. Lives entirely in the card&#39;s TSX code.</p><h2 id="requirements" tabindex="-1">Requirements <a class="header-anchor" href="#requirements" aria-label="Permalink to &quot;Requirements&quot;">​</a></h2><ul><li><strong>Scope</strong>: Card-specific (桜色の季節 TSX only)</li><li><strong>Purpose</strong>: Let players see available locations and their geographical layout</li><li><strong>Interaction</strong>: View-only, with hover/tap feedback on landmarks. Highlights current location.</li><li><strong>Style</strong>: Hand-drawn Japanese game map (CSS-only, no images)</li></ul><h2 id="geographical-layout" tabindex="-1">Geographical Layout <a class="header-anchor" href="#geographical-layout" aria-label="Permalink to &quot;Geographical Layout&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>        ⛩️ 神社 (hilltop, NW)</span></span>
<span class="line"><span>                                    🏫 学校 (hilltop, NE)</span></span>
<span class="line"><span>                                    🎀 陽菜の家 (near school)</span></span>
<span class="line"><span>        📚 凛の家 (quiet area, W)</span></span>
<span class="line"><span>                    🌸 樱花小路 (slope connecting school → town)</span></span>
<span class="line"><span>        🌳 公園 (center)            🏅 茉莉の家 (near park)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>                🛍️ 商店街 (south of park)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>                    🚉 車站 (south end)</span></span>
<span class="line"><span>                    🏠 自宅 (near station)</span></span></code></pre></div><p>Logic:</p><ul><li>Shrine on hilltop (classic Japanese town layout)</li><li>School on hill (name 桜ヶ丘 = cherry blossom hill)</li><li>Cherry path = slope from school to town center</li><li>陽菜&#39;s home nearest to school (childhood friend, walks to school together)</li><li>凛&#39;s home in quiet western residential area</li><li>茉莉&#39;s home near park (athletic character)</li><li>Player&#39;s home near station (just moved to town)</li></ul><h2 id="_10-landmarks" tabindex="-1">10 Landmarks <a class="header-anchor" href="#_10-landmarks" aria-label="Permalink to &quot;10 Landmarks&quot;">​</a></h2><table tabindex="0"><thead><tr><th>#</th><th>Landmark</th><th>Sub-locations</th><th>Map position</th></tr></thead><tbody><tr><td>1</td><td>⛩️ 桜ヶ丘神社</td><td>—</td><td>Top-left</td></tr><tr><td>2</td><td>🏫 桜ヶ丘学園</td><td>校门前・教室・走廊・图书馆・体育馆・操場・天台・会議室</td><td>Top-right</td></tr><tr><td>3</td><td>🌸 樱花小路</td><td>—</td><td>Upper-center</td></tr><tr><td>4</td><td>🌳 中央公園</td><td>—</td><td>Center</td></tr><tr><td>5</td><td>🛍️ 商店街</td><td>喫茶店・花店・便利店・食堂</td><td>Lower-center</td></tr><tr><td>6</td><td>🚉 桜ヶ丘駅</td><td>夕阳街道</td><td>Bottom-center</td></tr><tr><td>7</td><td>🏠 自宅</td><td>—</td><td>Bottom-right</td></tr><tr><td>8</td><td>🎀 陽菜の家</td><td>陽菜的房间</td><td>Upper-right (near school)</td></tr><tr><td>9</td><td>📚 凛の家</td><td>凛的房间</td><td>Middle-left</td></tr><tr><td>10</td><td>🏅 茉莉の家</td><td>茉莉的房间</td><td>Middle-right (near park)</td></tr></tbody></table><h2 id="currentbg-→-landmark-mapping" tabindex="-1">currentBg → Landmark Mapping <a class="header-anchor" href="#currentbg-→-landmark-mapping" aria-label="Permalink to &quot;currentBg → Landmark Mapping&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>school_gate, classroom, hallway, library, gym, track, rooftop, meeting_room → 学校</span></span>
<span class="line"><span>cherry_path → 樱花小路</span></span>
<span class="line"><span>shrine → 神社</span></span>
<span class="line"><span>park → 公園</span></span>
<span class="line"><span>cafe, flower_shop, convenience_store, cafeteria → 商店街</span></span>
<span class="line"><span>station, evening_street → 車站</span></span>
<span class="line"><span>home → 自宅</span></span>
<span class="line"><span>hina_room → 陽菜の家</span></span>
<span class="line"><span>rin_room → 凛の家</span></span>
<span class="line"><span>mari_room → 茉莉の家</span></span></code></pre></div><h2 id="visual-design" tabindex="-1">Visual Design <a class="header-anchor" href="#visual-design" aria-label="Permalink to &quot;Visual Design&quot;">​</a></h2><h3 id="overall" tabindex="-1">Overall <a class="header-anchor" href="#overall" aria-label="Permalink to &quot;Overall&quot;">​</a></h3><ul><li>Parchment background: <code>#f5e6c8</code> with CSS noise/grain texture</li><li>Title: 「桜ヶ丘 町内マップ」centered top, Ma Shan Zheng font</li><li>Dashed brown lines connecting landmarks (roads)</li><li>Subtle green gradient for hilltop areas</li><li>Cherry blossom petal decorations in corners</li></ul><h3 id="map-button" tabindex="-1">Map Button <a class="header-anchor" href="#map-button" aria-label="Permalink to &quot;Map Button&quot;">​</a></h3><ul><li>Fixed position: top-right corner of VN interface</li><li>Small circle, 🗺️ icon</li><li>Frosted glass style (backdrop-filter: blur), matching existing card UI</li></ul><h3 id="map-overlay" tabindex="-1">Map Overlay <a class="header-anchor" href="#map-overlay" aria-label="Permalink to &quot;Map Overlay&quot;">​</a></h3><ul><li>Fullscreen overlay, fade-in animation (200ms)</li><li>Close via: ✕ button / click blank area / Escape key</li><li>Does not block game state</li></ul><h3 id="landmark-cards" tabindex="-1">Landmark Cards <a class="header-anchor" href="#landmark-cards" aria-label="Permalink to &quot;Landmark Cards&quot;">​</a></h3><ul><li>Rounded card bubbles with emoji + name</li><li>Sub-locations listed below in small text, separated by ・</li><li>Normal state: 80% white bg + 1px light gray border</li><li>Current location: pink border <code>#f472b6</code> + pulse glow + 📍現在地 badge</li></ul><h3 id="hover-tap-feedback" tabindex="-1">Hover/Tap Feedback <a class="header-anchor" href="#hover-tap-feedback" aria-label="Permalink to &quot;Hover/Tap Feedback&quot;">​</a></h3><ul><li>Hover: <code>scale(1.08)</code> + deeper shadow + light pink border, transition 200ms ease</li><li>Click/Tap: brief <code>scale(0.95)</code> press → bounce to <code>scale(1.08)</code></li><li>Current-location landmark: same scale effect, keeps pink pulse border</li></ul><h2 id="implementation" tabindex="-1">Implementation <a class="header-anchor" href="#implementation" aria-label="Permalink to &quot;Implementation&quot;">​</a></h2><ul><li>All code inside the card&#39;s existing TSX (React.createElement, no JSX)</li><li>New state: <code>showMap</code> (boolean)</li><li>New constants: <code>LANDMARKS</code>, <code>BG_TO_LANDMARK</code></li><li>New function: <code>renderMap()</code> → returns overlay React element</li><li>Map button inserted into VN interface top-right area</li><li>Estimated ~250-350 lines of new code</li></ul><h2 id="not-in-scope" tabindex="-1">Not In Scope <a class="header-anchor" href="#not-in-scope" aria-label="Permalink to &quot;Not In Scope&quot;">​</a></h2><ul><li>No click-to-move navigation</li><li>No map zoom/drag</li><li>No dynamic unlock (all locations always visible)</li><li>No platform-level changes</li></ul>`,28)])])}const m=e(i,[["render",s]]);export{u as __pageData,m as default};
